SELECT sc.*, s.name as student_name, s.student_no, c.class_name, s.class_id as s_class_id, sub.subject_name, e.id as exam_id, e.exam_name
FROM score_info sc
LEFT JOIN student_info s ON sc.student_id = s.id
LEFT JOIN class_info c ON s.class_id = c.id
LEFT JOIN subject sub ON sc.subject_id = sub.id
LEFT JOIN exam e ON sc.exam_id = e.id
WHERE 1=1 AND sc.status = 1 AND s.status = 1

    AND sc.student_id = #{studentId}


    AND s.class_id = #{classId}


    AND sc.subject_id = #{subjectId}


    AND sc.subject_id IN

        #{sid}



    AND sc.exam_id = #{examId}


    AND sc.score >= #{minScore}


    AND sc.score <= #{maxScore}


    AND sc.exam_date = #{examDate}

ORDER BY s.student_no ASC, sc.exam_date DESC

SELECT sc.*, s.name as student_name, s.student_no, c.class_name, s.class_id as s_class_id, sub.subject_name, (SELECT SUM(score) FROM score_info WHERE student_id = sc.student_id AND status = 1) as total_score FROM score_info sc LEFT JOIN student_info s ON sc.student_id = s.id LEFT JOIN class_info c ON s.class_id = c.id LEFT JOIN subject sub ON sc.subject_id = sub.id WHERE 1=1 AND sc.status = 1
AND s.class_id = #{classId}
AND sc.subject_id IN
#{sid}
ORDER BY total_score DESC

SELECT sc.exam_date, sc.subject_id, sub.subject_name, AVG(sc.score) as score, COUNT(DISTINCT sc.student_id) as studentCount, s.class_id as s_class_id FROM score_info sc LEFT JOIN student_info s ON sc.student_id = s.id LEFT JOIN subject sub ON sc.subject_id = sub.id WHERE sc.status = 1 AND s.class_id = #{classId}
AND sc.subject_id IN
#{sid}
GROUP BY sc.exam_date, sc.subject_id, sub.subject_name, s.class_id ORDER BY sc.exam_date ASC
